// TNR jutsu builder bundle — loaded via @require by the tiny VM loader. Upload this file to GitHub.
// v3.2: rate-limit safe (throttle + backoff so volume sweeps don't trip the wall),
// preserves createdAt on edits (only stamps now() on brand-new jutsu), and the convert
// path now keeps real injected ids (only remaps kit srcIds) so sweeps don't corrupt effects.
(()=>{'use strict';if(window.__tnrBK)return;window.__tnrBK=1;
const MT={values:{"data.createdAt":["Date"],"data.updatedAt":["Date"]},v:1},now=()=>new Date().toISOString();
const THR=2000,sleep=m=>new Promise(r=>setTimeout(r,m));
const isLim=(s,t)=>s===429||/too fast|too many|rate limit|slow down|infraction/i.test(t||'');
const post=async(p,b)=>{const r=await fetch('/api/trpc/'+p+'?batch=1',{method:'POST',headers:{'content-type':'application/json'},credentials:'same-origin',body:JSON.stringify(b)});let t='';try{t=await r.text()}catch(e){}return{ok:r.ok,status:r.status,text:t}};
const postRL=async(p,b,wf)=>{let tr=0;while(1){const r=await post(p,b);if(isLim(r.status,r.text)){tr++;if(tr>8)return r;const w=Math.min(60000,5000*Math.pow(2,tr-1));wf&&wf(w,tr);await sleep(w);continue}return r}};
const rid=t=>(t.match(/"message":"([^"]+)"/)||[])[1],rerr=t=>{const m=t.match(/"message":"((?:[^"\\]|\\.)*)"/);return(m?m[1]:(t||'no body')).slice(0,300)};
const mk=wf=>postRL('jutsu.create',{"0":{json:null,meta:{values:["undefined"],v:1}}},wf);
const up=(id,d,wf)=>{const ca=d.createdAt||now();return postRL('jutsu.update',{"0":{json:{id,data:Object.assign({},d,{id,createdAt:ca,updatedAt:now()})},meta:MT}},wf)};
const MK='tnr_bk_idmap_v1',lm=()=>{try{return JSON.parse(localStorage.getItem(MK)||'{}')}catch(e){return{}}},sm=m=>{try{localStorage.setItem(MK,JSON.stringify(m))}catch(e){}};
let idmap=lm(),rows=[],$i,$l,$b,$s,$g,$r;
const bdg=r=>r.slot==='convert'?'convert':(idmap[r.key]?'reuse':'create');
const prog=()=>{const d=rows.filter(r=>r.state==='ok').length,e=rows.filter(r=>r.state==='error').length;$b.style.width=Math.round(d/(rows.length||1)*100)+'%';$r.style.display=e?'':'none'};
const draw=()=>{$l.textContent='';for(const r of rows){const el=document.createElement('div');el.className='k-rw s-'+r.state;el.innerHTML='<i class="k-dt"></i><b class="k-nm"></b><u class="k-bg"></u><s class="k-st"></s>';el.querySelector('.k-nm').textContent=r.name;el.querySelector('.k-bg').textContent=bdg(r);el.querySelector('.k-st').textContent=r.detail||r.state;el.onclick=()=>{if(r.detail&&r.detail.length>26)alert(r.name+'\n\n'+r.detail)};r.el=el;$l.appendChild(el)}prog()};
const sr=(r,st,dt)=>{r.state=st;if(dt!==undefined)r.detail=dt;if(r.el){r.el.className='k-rw s-'+st;r.el.querySelector('.k-bg').textContent=bdg(r);r.el.querySelector('.k-st').textContent=r.detail||st}prog()};
const parse=()=>{let m;try{m=JSON.parse($i.value)}catch(e){$s.textContent='❌ JSON: '+e.message;rows=[];$l.textContent='';$b.style.width='0%';return 0}const a=m.jutsu||[];if(!a.length){$s.textContent='❌ no jutsu';rows=[];$l.textContent='';return 0}rows=a.map(j=>({key:j.srcId,name:j.name,slot:j.slot,targetId:j.targetId,data:j.data,state:'pending',detail:''}));const c=rows.filter(r=>r.slot==='create').length,v=rows.filter(r=>r.slot==='convert').length,n=rows.reduce((x,r)=>x+((r.data.effects||[]).filter(e=>e.type==='injectjutsus').reduce((k,e)=>k+(e.jutsuIds||[]).length,0)),0);$s.textContent=rows.length+' jutsu · '+c+' create · '+v+' convert · '+n+' injects';draw();return 1};
const one=async(r,ph)=>{const wf=(w,tr)=>sr(r,'running','⏳ limited '+(w/1000|0)+'s·try'+tr);if(ph==='A'){sr(r,'running','creating…');let id=idmap[r.key];if(!id){const c=await mk(wf);id=rid(c.text);if(!c.ok||!id){sr(r,'error','create '+c.status+' '+rerr(c.text));return}idmap[r.key]=id;sm(idmap)}const u=await up(id,r.data,wf);u.ok?sr(r,'ok','→ '+id):sr(r,'error','fill '+u.status+' '+rerr(u.text))}else{sr(r,'running','converting…');const d=JSON.parse(JSON.stringify(r.data));for(const e of d.effects||[])if(e.type==='injectjutsus')e.jutsuIds=(e.jutsuIds||[]).map(s=>idmap[s]||s);const u=await up(r.targetId,d,wf);const j=(d.effects||[]).find(e=>e.type==='injectjutsus')||{};u.ok?sr(r,'ok','→ '+r.targetId+(j.jutsuIds?' · inj '+j.jutsuIds.length:'')):sr(r,'error',u.status+' '+rerr(u.text))}};
const build=async sub=>{const L=sub||rows;$g.disabled=$r.disabled=1;const A=L.filter(r=>r.slot==='create'),B=L.filter(r=>r.slot==='convert');$s.textContent='building… creates';for(let i=0;i<A.length;i++){await one(A[i],'A');if(i<A.length-1||B.length)await sleep(THR)}$s.textContent='building… converts';for(let i=0;i<B.length;i++){await one(B[i],'B');if(i<B.length-1)await sleep(THR)}const e=rows.filter(r=>r.state==='error').length;$s.textContent=e?('⚠ '+e+' error(s) — tap a red row, or Retry failed'):('✅ all '+rows.length+' built');$g.disabled=$r.disabled=0;ac()};
const lt=()=>rows.map(r=>(r.state==='ok'?'ok  ':r.state==='error'?'ERR ':'-   ')+r.name+'  '+(r.detail||r.state)).join('\n')+'\n\nID MAP:\n'+JSON.stringify(idmap,null,1);
const cp=()=>{const t=document.createElement('textarea');t.value=lt();t.style.cssText='position:fixed;left:-9999px';document.body.appendChild(t);t.focus();t.select();let o=0;try{o=document.execCommand('copy')}catch(e){}if(!o)try{navigator.clipboard&&navigator.clipboard.writeText(t.value)}catch(e){}t.remove()};
const ac=()=>{try{navigator.clipboard&&navigator.clipboard.writeText(lt())}catch(e){}};
const CSS='.k-fab{position:fixed;bottom:12px;left:12px;z-index:2147483000;background:#1f7c3b;color:#fff;border:0;border-radius:10px;padding:11px 16px;font:600 14px system-ui;box-shadow:0 4px 16px #0008}.k-pn{position:fixed;left:8px;right:8px;bottom:8px;z-index:2147483000;display:none;flex-direction:column;max-height:88vh;background:#16171b;color:#e8e8ea;border:1px solid #3a3b44;border-radius:14px;box-shadow:0 12px 44px #000a;font:13px system-ui;overflow:hidden}.k-hd{display:flex;align-items:center;gap:8px;padding:11px 12px;background:#202128;border-bottom:1px solid #34353d}.k-ti{flex:1;font-weight:700;font-size:15px}.k-ic{background:#34353d;color:#e8e8ea;border:0;border-radius:8px;padding:7px 12px;font-size:15px}.k-bw{height:4px;background:#2a2b32}.k-bar{height:100%;width:0;background:#2ec26a}.k-bd{padding:11px 12px;overflow:auto;overscroll-behavior:contain}.k-in{width:100%;box-sizing:border-box;height:13vh;min-height:64px;background:#0e0f12;color:#cde6ff;border:1px solid #34353d;border-radius:8px;padding:8px;font:12px monospace}.k-st2{margin:9px 2px;font-size:12px;min-height:16px}.k-ls{display:flex;flex-direction:column;gap:5px}.k-rw{display:flex;align-items:center;gap:8px;padding:9px 10px;background:#1b1c22;border:1px solid #2a2b33;border-radius:8px}.k-dt{width:9px;height:9px;border-radius:50%;background:#6b6c74;flex:none}.k-nm{flex:1;font:600 12px system-ui;white-space:nowrap;overflow:hidden;text-overflow:ellipsis}.k-bg{font-size:10px;padding:2px 8px;border-radius:999px;background:#33343d;flex:none;font-style:normal}.k-st{font-size:11px;opacity:.85;max-width:44%;white-space:nowrap;overflow:hidden;text-overflow:ellipsis;flex:none;text-decoration:none}.s-running .k-dt{background:#e6b800}.s-ok .k-dt{background:#2ec26a}.s-error .k-dt{background:#ec5b5b}.s-error{border-color:#5a2a2a}.k-ft{display:flex;gap:8px;padding:10px 12px;background:#1b1c22;border-top:1px solid #34353d;flex-wrap:wrap}.k-bt{flex:1;min-width:92px;border:0;border-radius:9px;padding:12px;font:600 13px system-ui;color:#fff}.k-go{background:#1f7c3b}.k-rt{background:#8a5a00;display:none}.k-cp{background:#2b4d70}.k-rs{background:#5a2a2a}';
const H=document.createElement('div');H.id='tnr-bk-host';const R=H.attachShadow({mode:'open'});
R.innerHTML='<style>'+CSS+'</style><button class="k-fab">▶ Build kit</button><div class="k-pn"><div class="k-hd"><span class="k-ti">Jutsu builder</span><button class="k-ic k-min">—</button></div><div class="k-bw"><div class="k-bar"></div></div><div class="k-bd"><textarea class="k-in" placeholder="paste a manifest (kit or sweep) json"></textarea><div class="k-st2">paste a manifest to preview</div><div class="k-ls"></div></div><div class="k-ft"><button class="k-bt k-go">▶ Build</button><button class="k-bt k-rt">↻ Retry failed</button><button class="k-bt k-cp">⧉ Copy</button><button class="k-bt k-rs">⌫ Reset</button></div></div>';
document.body.appendChild(H);const q=s=>R.querySelector(s),pn=q('.k-pn'),fb=q('.k-fab');
$i=q('.k-in');$l=q('.k-ls');$b=q('.k-bar');$s=q('.k-st2');$g=q('.k-go');$r=q('.k-rt');
const sh=v=>{pn.style.display=v?'flex':'none';fb.style.display=v?'none':'block'};
fb.onclick=()=>sh(1);q('.k-min').onclick=()=>sh(0);$i.addEventListener('input',parse);
$g.onclick=()=>{if(parse())build()};$r.onclick=()=>build(rows.filter(r=>r.state==='error'));
q('.k-cp').onclick=()=>{cp();$s.textContent='📋 copied'};
q('.k-rs').onclick=()=>{if(confirm('Clear remembered ids? Next build creates fresh records.')){idmap={};sm(idmap);draw();$s.textContent='memory cleared'}};
new MutationObserver(()=>{if(!document.getElementById('tnr-bk-host'))document.body.appendChild(H)}).observe(document.body,{childList:1});
})();
